  "std:fmt": "// `std:fmt` — pure-VL formatting helpers over the intrinsic floor\n// (docs/std-design.md D4 item 1). Imports nothing: strings are built with\n// `+`/`.slice` and rendered digit by digit. The exported helpers take a\n// `self` first parameter, so they read as UFCS methods on the receiver\n// (`n.toStr()`, `parts.join(sep)`). f64→string (shortest round-trip,\n// Ryu-class) is deliberately absent — `print` keeps covering floats.\n\n// Decimal digit d in 0..=9 as its character. Takes i64 so both integer\n// widths share one renderer (i64 cannot narrow to i32, so a string-index\n// lookup is not expressible for the wide path).\nfunction digitChar(d: i64): string {\n  if d == 0 { return \"0\" }\n  if d == 1 { return \"1\" }\n  if d == 2 { return \"2\" }\n  if d == 3 { return \"3\" }\n  if d == 4 { return \"4\" }\n  if d == 5 { return \"5\" }\n  if d == 6 { return \"6\" }\n  if d == 7 { return \"7\" }\n  if d == 8 { return \"8\" }\n  \"9\"\n}\n\n// Decimal rendering of any i64, including i64 min. The accumulator works in\n// the NEGATIVE range (positive inputs are negated first) because the negative\n// range covers i64 min, whose magnitude overflows when negated; `%` on a\n// negative operand yields a digit in -9..=0, negated back per digit.\nfunction renderI64(n: i64): string {\n  if n == 0 { return \"0\" }\n  const zero: i64 = 0\n  let m: i64 = n\n  if m > 0 { m = zero - m }\n  let out = \"\"\n  while m < 0 {\n    out = digitChar(zero - (m % 10)) + out\n    m = m / 10\n  }\n  if n < 0 { out = \"-\" + out }\n  out\n}\n\n// Decimal rendering of an integer via its receiver: `n.toStr()` over an i32\n// or i64 binding. One union receiver covers both widths (UFCS resolves by\n// `self`+arity; the value boxes in, `is`-narrows out); i32 widens losslessly\n// into the shared i64 renderer. The boolean arm renders true/false.\nexport function toStr(self: i32 | i64 | boolean): string {\n  if self is boolean {\n    if self { return \"true\" }\n    return \"false\"\n  }\n  if self is i32 {\n    const wide: i64 = self\n    return renderI64(wide)\n  }\n  return renderI64(self)\n}\n\n// `self` concatenated n times; n <= 0 yields \"\".\nexport function repeat(self: string, n: i32): string {\n  let out = \"\"\n  let i = 0\n  while i < n {\n    out = out + self\n    i = i + 1\n  }\n  out\n}\n\n// Pads `self` on the left with `fill` up to `width`. A multi-codepoint fill is\n// tiled and truncated so the result is exactly `width` long; returns `self`\n// unchanged when it is already wide enough or when fill is empty.\nexport function padLeft(self: string, width: i32, fill: string): string {\n  if fill.length == 0 { return self }\n  const deficit = width - self.length\n  if deficit <= 0 { return self }\n  let pad = \"\"\n  let have = 0\n  while have < deficit {\n    pad = pad + fill\n    have = have + fill.length\n  }\n  return pad.slice(0, deficit) + self\n}\n\n// Elements of `self` concatenated with `sep` between consecutive elements.\nexport function join(self: string[], sep: string): string {\n  let out = \"\"\n  let i = 0\n  while i < self.length {\n    if i > 0 { out = out + sep }\n    out = out + self[i]\n    i = i + 1\n  }\n  out\n}\n",
